INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('나이아신아마이드', 'Niacinamide (Vitamin B3)', 'brightening', 5, '피지 조절, 미백, 모공 축소, 피부장벽 강화에 효과적인 만능 성분', '고농도(10%+) 사용 시 민감피부에 자극 가능, 비타민C와 분리 사용 권장', '{"oily","combination","normal","sensitive","dry"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('비타민C', 'Ascorbic Acid (L-Ascorbic Acid)', 'brightening', 3, '강력한 항산화, 멜라닌 생성 억제, 콜라겐 합성 촉진으로 피부톤 균일화', '산화에 취약하여 개봉 후 빠르게 사용, pH 의존적이라 산성 환경 필요', '{"normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('아르부틴', 'Arbutin (Alpha-Arbutin)', 'brightening', 4, '멜라닌 합성 억제를 통한 미백, 기미/잡티 완화에 효과적', '하이드로퀴논 유도체로 고농도 시 자극 가능, 알파아르부틴이 더 안정적', '{"normal","dry","combination","sensitive"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('트라넥삼산', 'Tranexamic Acid', 'brightening', 4, '색소침착 개선, 기미/잡티 완화, 멜라닌 전달 억제에 효과적', '대부분 안전하나 경구 복용 시 전문의 상담 필요, 외용은 저자극', '{"normal","dry","combination","sensitive","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('글루타치온', 'Glutathione', 'brightening', 4, '강력한 항산화 및 미백 효과, 멜라닌 생성 억제와 피부톤 개선', '안정성이 낮아 제형에 따라 효능 차이 큼, 피부 흡수율 고려 필요', '{"normal","dry","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('레티놀', 'Retinol (Vitamin A)', 'anti-aging', 2, '주름 개선, 콜라겐 촉진, 세포 턴오버 증가로 피부 재생 효과 탁월', '자외선 민감 증가, 건조/벗겨짐 가능, 반드시 야간 사용 + 선크림 필수', '{"normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('아데노신', 'Adenosine', 'anti-aging', 5, '주름 개선 기능성 고시 성분, 상처 회복 촉진 및 항염 효과', '특별한 주의 없음, 대부분의 성분과 안전하게 병용 가능', '{"normal","dry","combination","sensitive","oily"}') ON CONFLICT (name_ko) DO NOTHING;
