INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('히알루론산', 'Hyaluronic Acid (Sodium Hyaluronate)', 'moisturizing', 5, '자기 무게 1000배 수분 보유, 피부 탄력 개선 및 즉각적인 수분 공급', '건조한 환경에서는 오히려 피부 수분을 빼앗길 수 있으므로 크림으로 봉인 필수', '{"dry","normal","combination","sensitive","oily"}') ON CONFLICT (name_ko) DO NOTHING;
