INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('센텔라', 'Centella Asiatica Extract (Cica)', 'soothing', 5, '피부 진정, 장벽 회복, 트러블 완화, 콜라겐 합성 촉진 효과', '극히 드물게 접촉 알레르기, 대부분의 성분과 안전하게 병용 가능', '{"sensitive","dry","normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('알란토인', 'Allantoin', 'soothing', 5, '피부 진정, 자극 완화, 각질 연화, 세포 재생 촉진 효과', '매우 순한 성분으로 특별한 주의 없음', '{"sensitive","dry","normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('알파비사보롤', 'Alpha-Bisabolol', 'soothing', 5, '캐모마일 유래 진정 성분, 항염/항균/피부 진정 효과 우수', '특별한 주의 없음, 민감피부에도 안전하게 사용 가능', '{"sensitive","dry","normal","combination"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('마데카소사이드', 'Madecassoside', 'soothing', 5, '센텔라 핵심 활성 성분, 진정/항염/콜라겐 합성 촉진에 탁월', '특별한 주의 없음, 손상 피부 회복에 최적', '{"sensitive","dry","normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('녹차추출물', 'Green Tea Extract (Camellia Sinensis)', 'antioxidant', 5, '폴리페놀 풍부한 항산화, 피지 조절, 항염, 자외선 손상 방어 효과', '매우 안전, 카페인에 민감한 경우 드물게 자극 가능', '{"oily","combination","normal","sensitive"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('토코페롤', 'Tocopherol (Vitamin E)', 'antioxidant', 5, '지용성 항산화제, 비타민C 효과 증대, 피부 보호 및 보습 효과', '순한 편이나 지성피부에 과량 사용 시 모공 막힘 가능', '{"dry","normal","combination","sensitive"}') ON CONFLICT (name_ko) DO NOTHING;
