INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('살리실산', 'Salicylic Acid (BHA)', 'exfoliating', 3, '지용성 각질 제거로 모공 속까지 침투, 블랙헤드/피지 관리에 효과적', '건조/자극 가능, 과도한 사용 금지, AHA/레티놀과 동시 사용 주의', '{"oily","combination"}') ON CONFLICT (name_ko) DO NOTHING;
INSERT INTO ingredients (name_ko, name_en, category, safety_score, efficacy, caution, skin_types) VALUES ('글리콜산', 'Glycolic Acid (AHA)', 'exfoliating', 3, '가장 작은 분자의 AHA로 깊은 침투, 각질 제거 및 피부결 개선 효과', '선크림 필수, 레티놀과 같은 날 사용 금지, 민감피부 농도 주의', '{"normal","combination","oily"}') ON CONFLICT (name_ko) DO NOTHING;
